-- Migration 003: Sprint 3 additions-- hasta_portal_tokens tableCREATE TABLE IF NOT EXISTS hasta_portal_tokens (  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),  token_hash TEXT NOT NULL UNIQUE,  doctor_id UUID REFERENCES auth.users(id) NOT NULL,  patient_id UUID REFERENCES patients(id) NOT NULL,  expires_at TIMESTAMPTZ NOT NULL,  last_accessed TIMESTAMPTZ,  created_at TIMESTAMPTZ DEFAULT NOW());CREATE INDEX IF NOT EXISTS idx_portal_tokens_hash ON hasta_portal_tokens(token_hash);CREATE INDEX IF NOT EXISTS idx_portal_tokens_expires ON hasta_portal_tokens(expires_at);-- RLS for hasta_portal_tokensALTER TABLE hasta_portal_tokens ENABLE ROW LEVEL SECURITY;CREATE POLICY IF NOT EXISTS portal_tokens_doctor ON hasta_portal_tokens  FOR ALL USING (auth.uid() = doctor_id);-- RLS for tables created in migration 002 (add if missing)ALTER TABLE IF EXISTS hasta_belgeler ENABLE ROW LEVEL SECURITY;ALTER TABLE IF EXISTS hasta_goruntulemeler ENABLE ROW LEVEL SECURITY;ALTER TABLE IF EXISTS hasta_ilaclar ENABLE ROW LEVEL SECURITY;ALTER TABLE IF EXISTS hasta_lab_sonuclari ENABLE ROW LEVEL SECURITY;ALTER TABLE IF EXISTS hasta_hatirlatma ENABLE ROW LEVEL SECURITY;DO $$ BEGIN  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='hasta_belgeler' AND policyname='belgeler_doctor') THEN    CREATE POLICY belgeler_doctor ON hasta_belgeler FOR ALL USING (auth.uid() = doctor_id);  END IF;  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='hasta_goruntulemeler' AND policyname='goruntuleme_doctor') THEN    CREATE POLICY goruntuleme_doctor ON hasta_goruntulemeler FOR ALL USING (auth.uid() = doctor_id);  END IF;  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='hasta_ilaclar' AND policyname='ilaclar_doctor') THEN    CREATE POLICY ilaclar_doctor ON hasta_ilaclar FOR ALL USING (auth.uid() = doctor_id);  END IF;  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='hasta_hatirlatma' AND policyname='hatirlatma_doctor') THEN    CREATE POLICY hatirlatma_doctor ON hasta_hatirlatma FOR ALL USING (auth.uid() = doctor_id);  END IF;END $$;